static common_chat_params common_chat_params_init_HANDLER_NAME(
    const common_chat_template & tmpl,
    const autoparser::generation_params & inputs) {

    common_chat_params data;

    // 1. Apply template to generate prompt
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);

    // 2. Set format (usually PEG parser)
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    // 3. List special tokens to preserve during tokenization
    data.preserved_tokens = {
        "[SPECIAL_TOKEN_1]",
        "[SPECIAL_TOKEN_2]",
    };

    // 4. Build PEG parser for output parsing
    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        // Define parser rules for expected output format
        // Handle content, tool calls, reasoning, etc.
        return /* final parser expression */;
    });

    data.parser = parser.save();

    // 5. Build grammar constraints (optional)
    if (include_grammar) {
        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                // Define schema constraints for each tool
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        // Define grammar triggers (when to activate grammar constraints)
        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
        };
    }

    return data;
}
```

